//! Embedded snapshot of the ISO 10383 Market Identifier Code (MIC) registry.
//!
//! This module is pure reference data: a dated, sorted, `no_std`-clean table
//! of every MIC published in the ISO 10383 registry, with no allocation and no
//! runtime dependency. It is compiled in only when the default `mic-registry`
//! feature is enabled; disable that feature for a build that validates MIC
//! *structure* only.
//!
//! A MIC is a four-character code identifying a securities trading venue or
//! market-data provider. The registry distinguishes an **operating MIC**,
//! which names a market operator, from a **segment MIC**, which names a
//! sub-market and references its operating MIC. Structural validation alone
//! cannot confirm a MIC exists — only membership in this registry can.
//!
//! # Snapshot
//!
//! - Source: ISO 10383 registry, published by SWIFT as the ISO 10383
//!   Registration Authority.
//! - Snapshot date: 2026-05-22 (see [`SNAPSHOT_DATE`](crate::mic_registry::SNAPSHOT_DATE)).
//! - Entries: 2853 (2289 with status `Active`).
//!
//! The registry is factual reference data; it is reproduced here verbatim and
//! is not a derivative work. Re-export this snapshot's currency from
//! [`SNAPSHOT_DATE`](crate::mic_registry::SNAPSHOT_DATE) when reporting validity to an auditor.
//!
//! # References
//!
//! - ISO 10383:2012, *Securities and related financial instruments — Codes
//!   for exchanges and market identification (MIC)*.
//! - ISO 10383 Registration Authority (SWIFT), Market Identifier Codes
//!   registry, snapshot 2026-05-22.

/// Lifecycle status of a registered MIC, as published in the ISO 10383
/// registry's `STATUS` column.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum MicStatus {
    /// The MIC is in active use.
    Active,
    /// The MIC has been retired and is no longer in use.
    Expired,
    /// The MIC's registry record was updated in the latest revision.
    Updated,
}

/// One entry of the ISO 10383 registry: a MIC and its descriptive metadata.
///
/// Every field is a `&'static str` into this crate's read-only data segment,
/// so a `MicEntry` is `Copy` and costs nothing to pass or store.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct MicEntry {
    /// The four-character Market Identifier Code.
    pub mic: &'static str,
    /// The operating MIC this code belongs to. For an operating MIC this
    /// equals [`mic`](Self::mic); for a segment MIC it names the parent.
    pub operating_mic: &'static str,
    /// `true` if this is an operating MIC (`OPRT`), `false` if a segment
    /// MIC (`SGMT`).
    pub is_operating: bool,
    /// Market name or institution description.
    pub name: &'static str,
    /// ISO 3166-1 alpha-2 country code of the venue, or `""` if the registry
    /// records none.
    pub country: &'static str,
    /// City of the venue, or `""` if the registry records none.
    pub city: &'static str,
    /// Registry lifecycle status.
    pub status: MicStatus,
}

/// Date of the ISO 10383 registry snapshot embedded in this module,
/// `YYYY-MM-DD`.
pub const SNAPSHOT_DATE: &str = "2026-05-22";

/// Looks up a MIC in the embedded ISO 10383 registry snapshot.
///
/// `mic` is matched exactly: it must be the upper-case four-character code.
/// The lookup is a binary search over [`REGISTRY`], which is sorted by MIC.
///
/// # Examples
///
/// ```
/// use regit_identifiers::mic_registry::lookup;
///
/// let nasdaq = lookup("XNAS").expect("XNAS is registered");
/// assert_eq!(nasdaq.country, "US");
/// assert!(nasdaq.is_operating);
///
/// assert!(lookup("ZZZZ").is_none());
/// ```
#[must_use]
pub fn lookup(mic: &str) -> Option<&'static MicEntry> {
    REGISTRY
        .binary_search_by(|entry| entry.mic.cmp(mic))
        .ok()
        .map(|index| &REGISTRY[index])
}

