#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn registry_is_non_empty() {
        assert_eq!(REGISTRY.len(), 2853);
    }

    #[test]
    fn active_entry_count_matches_snapshot() {
        let active = REGISTRY
            .iter()
            .filter(|entry| entry.status == MicStatus::Active)
            .count();
        assert_eq!(active, 2289);
    }

    #[test]
    fn registry_is_sorted_and_unique() {
        for pair in REGISTRY.windows(2) {
            assert!(
                pair[0].mic < pair[1].mic,
                "registry must be strictly sorted by MIC"
            );
        }
    }

    #[test]
    fn every_mic_is_four_upper_alnum() {
        for entry in REGISTRY {
            assert_eq!(entry.mic.len(), 4);
            assert!(
                entry
                    .mic
                    .bytes()
                    .all(|b| b.is_ascii_uppercase() || b.is_ascii_digit()),
                "MIC {} is not 4 upper-case alphanumerics",
                entry.mic
            );
        }
    }

    #[test]
    fn lookup_finds_known_operating_mic() {
        let nasdaq = lookup("XNAS").expect("XNAS is registered");
        assert_eq!(nasdaq.mic, "XNAS");
        assert_eq!(nasdaq.country, "US");
        assert!(nasdaq.is_operating);
        assert_eq!(nasdaq.status, MicStatus::Active);
    }

    #[test]
    fn lookup_rejects_unregistered_code() {
        assert!(lookup("ZZZZ").is_none());
    }

    #[test]
    fn lookup_is_case_sensitive_uppercase() {
        assert!(lookup("xnas").is_none());
    }

    #[test]
    fn snapshot_date_is_iso_format() {
        assert_eq!(SNAPSHOT_DATE.len(), 10);
        assert_eq!(SNAPSHOT_DATE, "2026-05-22");
    }

    #[test]
    fn operating_mic_is_self_for_operating_entries() {
        for entry in REGISTRY {
            if entry.is_operating {
                assert_eq!(entry.mic, entry.operating_mic);
            }
        }
    }
}
